/*
 * Multi-function libm test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly  (test_opt.elf)
 *   2. Linked with toolchain's default libm  (test_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#define PX(v) ((unsigned long)f2u(v))

/* ------------------------------------------------------------------ */
/* Standard test inputs                                                */
/* ------------------------------------------------------------------ */

/* General inputs: covers specials, denorms, small, medium, large */
static const uint32_t general_bits[] = {
    /* zeros */
    0x00000000u, 0x80000000u,
    /* NaN, Inf */
    0x7fc00000u, 0x7f800001u, 0xffc00000u,
    0x7f800000u, 0xff800000u,
    /* denorms */
    0x00000001u, 0x80000001u, 0x00400000u, 0x007fffffu,
    /* tiny */
    0x26901d7du, /* 1e-15f */
    0x2edbe6ffu, /* 1e-10f */
};

/* Normal-range values for trig/general functions */
static const float normal_vals[] = {
    0.0f, -0.0f,
    0.1f, -0.1f, 0.5f, -0.5f, 1.0f, -1.0f,
    1.5f, -1.5f, 2.0f, -2.0f, 3.0f, -3.0f,
    0.78539816f,  /* pi/4 */
    1.57079633f,  /* pi/2 */
    3.14159265f,  /* pi */
    6.28318531f,  /* 2*pi */
    10.0f, -10.0f, 100.0f, -100.0f,
    1000.0f, -1000.0f,
    1.0e10f, -1.0e10f,
    FLT_MAX, -FLT_MAX,
};
#define N_NORMAL (sizeof(normal_vals) / sizeof(normal_vals[0]))

/* Positive-only inputs for log, sqrt, etc. */
static const float pos_vals[] = {
    0.0f,
    0.001f, 0.01f, 0.1f, 0.5f, 0.99f,
    1.0f, 1.01f, 1.5f, 2.0f, 3.14159265f,
    10.0f, 100.0f, 1000.0f, 1.0e10f, 1.0e20f,
    FLT_MAX,
};
#define N_POS (sizeof(pos_vals) / sizeof(pos_vals[0]))

/* [-1, 1] inputs for asin, acos */
static const float unit_vals[] = {
    -1.0f, -0.999f, -0.99f, -0.9f, -0.5f, -0.1f,
    0.0f,
    0.1f, 0.5f, 0.9f, 0.99f, 0.999f, 1.0f,
    /* outside domain — should produce NaN */
    1.5f, -1.5f, 2.0f,
};
#define N_UNIT (sizeof(unit_vals) / sizeof(unit_vals[0]))

/* Sweep helper: n evenly-spaced points in [lo, hi] */
static void sweep(const char *tag, float (*fn)(float), float lo, float hi, int n)
{
    float step = (hi - lo) / (float)n;
    for (int i = 0; i <= n; i++) {
        float x = lo + (float)i * step;
        float r = fn(x);
        printf("%s %08lx %08lx\n", tag, PX(x), PX(r));
    }
}

/* ------------------------------------------------------------------ */
/* Per-function testers                                                */
/* ------------------------------------------------------------------ */

/* float f(float) — general domain */
static void test_ff(const char *name, float (*fn)(float))
{
    /* specials & denorms */
    for (unsigned i = 0; i < sizeof(general_bits)/sizeof(general_bits[0]); i++) {
        float x = u2f(general_bits[i]);
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    /* normal range */
    for (unsigned i = 0; i < N_NORMAL; i++) {
        float x = normal_vals[i];
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    /* sweep */
    sweep(name, fn, -12.56637f, 12.56637f, 200);
}

/* float f(float) — positive domain (log, sqrt) */
static void test_ff_pos(const char *name, float (*fn)(float))
{
    /* specials & denorms */
    for (unsigned i = 0; i < sizeof(general_bits)/sizeof(general_bits[0]); i++) {
        float x = u2f(general_bits[i]);
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    /* positive values */
    for (unsigned i = 0; i < N_POS; i++) {
        float x = pos_vals[i];
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    sweep(name, fn, 0.001f, 1000.0f, 200);
}

/* float f(float) — [-1,1] domain (asin, acos) */
static void test_ff_unit(const char *name, float (*fn)(float))
{
    for (unsigned i = 0; i < sizeof(general_bits)/sizeof(general_bits[0]); i++) {
        float x = u2f(general_bits[i]);
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    for (unsigned i = 0; i < N_UNIT; i++) {
        float x = unit_vals[i];
        printf("%s %08lx %08lx\n", name, PX(x), PX(fn(x)));
    }
    sweep(name, fn, -1.0f, 1.0f, 200);
}

/* fmodf(x, y) */
static void test_fmod(void)
{
    static const float xs[] = { 0.0f, 1.0f, -1.0f, 5.5f, -5.5f, 100.0f, FLT_MAX };
    static const float ys[] = { 1.0f, -1.0f, 0.3f, 2.0f, 3.14159265f, FLT_MIN };
    int nx = sizeof(xs)/sizeof(xs[0]);
    int ny = sizeof(ys)/sizeof(ys[0]);
    for (int i = 0; i < nx; i++)
        for (int j = 0; j < ny; j++) {
            float r = fmodf(xs[i], ys[j]);
            printf("fmodf %08lx %08lx %08lx\n", PX(xs[i]), PX(ys[j]), PX(r));
        }
    /* fmod(x, 0) and fmod(inf, y) */
    printf("fmodf %08lx %08lx %08lx\n", PX(1.0f), PX(0.0f), PX(fmodf(1.0f, 0.0f)));
    printf("fmodf %08lx %08lx %08lx\n", PX(u2f(0x7f800000u)), PX(1.0f),
           PX(fmodf(u2f(0x7f800000u), 1.0f)));
}

/* powf(x, y) */
static void test_pow(void)
{
    static const float bases[] = { 0.0f, 0.5f, 1.0f, 2.0f, 10.0f, 100.0f, -1.0f, -2.0f };
    static const float exps[]  = { 0.0f, 0.5f, 1.0f, 2.0f, 3.0f, -1.0f, -2.0f, 10.0f, 0.1f };
    int nb = sizeof(bases)/sizeof(bases[0]);
    int ne = sizeof(exps)/sizeof(exps[0]);
    for (int i = 0; i < nb; i++)
        for (int j = 0; j < ne; j++) {
            float r = powf(bases[i], exps[j]);
            printf("powf %08lx %08lx %08lx\n", PX(bases[i]), PX(exps[j]), PX(r));
        }
