static void test_frexp(void)
{
    for (unsigned i = 0; i < N_NORMAL; i++) {
        float x = normal_vals[i];
        int ex;
        float r = frexpf(x, &ex);
        printf("frexpf %08lx %08lx %d\n", PX(x), PX(r), ex);
    }
}

/* ldexpf */
static void test_ldexp(void)
{
    static const float bases[] = { 0.0f, 0.5f, 1.0f, -1.0f, 1.5f, FLT_MIN, FLT_MAX };
    static const int exps[] = { 0, 1, -1, 10, -10, 50, -50, 127, -126 };
