    static const int exps[] = { 0, 1, -1, 10, -10, 50, -50, 127, -126 };
    int nb = sizeof(bases)/sizeof(bases[0]);
    int ne = sizeof(exps)/sizeof(exps[0]);
    for (int i = 0; i < nb; i++)
        for (int j = 0; j < ne; j++) {
            float r = ldexpf(bases[i], exps[j]);
