 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly  (test_opt.elf)
 *   2. Linked with toolchain's default libm  (test_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#define PX(v) ((unsigned long)f2u(v))

/* Shared test inputs */
static const float vals[] = {
    0.0f, -0.0f,
    0.1f, -0.1f, 0.5f, -0.5f, 1.0f, -1.0f,
    1.5f, -1.5f, 2.0f, -2.0f, 3.0f, -3.0f,
    0.78539816f,  /* pi/4 */
    1.57079633f,  /* pi/2 */
    3.14159265f,  /* pi */
    6.28318531f,  /* 2*pi */
    10.0f, -10.0f, 100.0f, -100.0f,
    1000.0f, -1000.0f,
    1.0e10f, -1.0e10f,
    FLT_MAX, -FLT_MAX,
};
#define NVALS (sizeof(vals) / sizeof(vals[0]))

static const uint32_t special_bits[] = {
    0x00000001u, /* min denorm */
    0x80000001u,
    0x00400000u, /* mid denorm */
    0x007fffffu, /* max denorm */
    0x7fc00000u, /* qNaN */
    0x7f800000u, /* +Inf */
    0xff800000u, /* -Inf */
};
#define NSPECIAL (sizeof(special_bits) / sizeof(special_bits[0]))

/* ------------------------------------------------------------------ */

#define TEST1(name, func) do { \
    for (unsigned i = 0; i < NSPECIAL; i++) { \
        float x = u2f(special_bits[i]); \
        printf(name " %08lx %08lx\n", PX(x), PX(func(x))); \
    } \
    for (unsigned i = 0; i < NVALS; i++) { \
        float x = vals[i]; \
        printf(name " %08lx %08lx\n", PX(x), PX(func(x))); \
    } \
} while(0)

int main(void)
{
    /* --- float f(float), general domain --- */
    TEST1("sinf",   sinf);
    TEST1("cosf",   cosf);
    TEST1("tanf",   tanf);
    TEST1("atanf",  atanf);
    TEST1("fabsf",  fabsf);
    TEST1("ceilf",  ceilf);
    TEST1("floorf", floorf);
    TEST1("expf",   expf);
    TEST1("sinhf",  sinhf);
    TEST1("coshf",  coshf);
    TEST1("tanhf",  tanhf);
    TEST1("logf",   logf);
    TEST1("log10f", log10f);
    TEST1("sqrtf",  sqrtf);
    TEST1("asinf",  asinf);
    TEST1("acosf",  acosf);

    /* --- fmodf(x, y) --- */
    {
        float ys[] = { 0.3f, 1.0f, 2.0f, 3.14159265f };
        int ny = sizeof(ys) / sizeof(ys[0]);
        for (unsigned i = 0; i < NVALS; i++)
            for (int j = 0; j < ny; j++)
                printf("fmodf %08lx %08lx %08lx\n",
                       PX(vals[i]), PX(ys[j]), PX(fmodf(vals[i], ys[j])));
    }

    /* --- powf(x, y) --- */
    {
        float exps[] = { 0.0f, 0.5f, 1.0f, 2.0f, -1.0f, 10.0f };
        int ne = sizeof(exps) / sizeof(exps[0]);
        for (unsigned i = 0; i < NVALS; i++)
            for (int j = 0; j < ne; j++)
                printf("powf %08lx %08lx %08lx\n",
                       PX(vals[i]), PX(exps[j]), PX(powf(vals[i], exps[j])));
    }

    /* --- frexpf --- */
    for (unsigned i = 0; i < NVALS; i++) {
        int ex;
        float r = frexpf(vals[i], &ex);
        printf("frexpf %08lx %08lx %d\n", PX(vals[i]), PX(r), ex);
    }

    /* --- ldexpf --- */
    {
        int exps[] = { 0, 1, -1, 10, -10, 127, -126 };
        int ne = sizeof(exps) / sizeof(exps[0]);
        for (unsigned i = 0; i < NVALS; i++)
            for (int j = 0; j < ne; j++)
                printf("ldexpf %08lx %d %08lx\n",
                       PX(vals[i]), exps[j], PX(ldexpf(vals[i], exps[j])));
    }

    /* --- modff --- */
    for (unsigned i = 0; i < NVALS; i++) {
        float ipart;
        float fpart = modff(vals[i], &ipart);
        printf("modff %08lx %08lx %08lx\n", PX(vals[i]), PX(ipart), PX(fpart));
    }

    /* --- fpclassify --- */
    for (unsigned i = 0; i < NSPECIAL; i++) {
        float x = u2f(special_bits[i]);
        printf("fpclassify %08lx %d\n", PX(x), fpclassify(x));
    }
    for (unsigned i = 0; i < NVALS; i++)
        printf("fpclassify %08lx %d\n", PX(vals[i]), fpclassify(vals[i]));

    return 0;
}

