/*
 * frexpf() test harness — prints (input_hex, output_hex) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

int main(void)
{
    float vals[] = {
        0.0f, -0.0f, 0.5f, -0.5f, 1.0f, -1.0f,
        1.5f, 2.0f, 3.14159265f, 100.0f, -100.0f,
        FLT_MIN, FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        int ex;
        float r = frexpf(vals[i], &ex);
        printf("%08lx %08lx %d\n",
               (unsigned long)f2u(vals[i]), (unsigned long)f2u(r), ex);
    }
    /* specials */
    {
        int ex;
        float x, r;
        x = u2f(0x7fc00000u); r = frexpf(x, &ex);
        printf("%08lx %08lx %d\n", (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
        x = u2f(0x7f800000u); r = frexpf(x, &ex);
        printf("%08lx %08lx %d\n", (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
        x = u2f(0x00000001u); r = frexpf(x, &ex);
        printf("%08lx %08lx %d\n", (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
    }
    return 0;
}
